@database("test4");

@meta({
    name: "users";
    description: "No puede estar vacio";
});

@columns({
    id: { 
        type: "int";
        options: ["primary", "autoincrement"];
    };
    name: { 
        type: "varchar";
        length: "255";
        options: ["not null"];
    };
    full_name: {
        type: "string";
        value: @compute(()=>{ 
            const name = @column(name) + " - " + @column(id) + new Date();
            return name;
        });
    };
});
